define(["mod_videoassessment/utils"],function(e){return{upload(t,o){const n=new FormData(document.querySelector("#mform")),d=e.getFileName(o.split("/")[1]);n.append("isRecordVideo",1),n.append(o.startsWith("audio")?"audio":"video",t,d);const i=document.querySelector("#mform").getAttribute("action"),s=n.get("id"),a=new XMLHttpRequest;a.open("POST",i),a.onload=(()=>{200===a.status&&(window.location.href=`${i}?id=${s}`)}),a.send(n)}}});